import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

export default async function handler(req, res) {
  // Verificação de segredo para evitar disparos externos maliciosos
  if (req.headers.authorization !== `Bearer ${process.env.CRON_SECRET}`) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    console.log('Running cleanup for expired waiting list reservations...');

    // Call the postgres function to process expirations
    const { data, error } = await supabase.rpc('fn_limpar_reservas_expiradas');

    if (error) throw error;

    return res.status(200).json({ 
      message: 'Cleanup processed successfully', 
      result: data 
    });
  } catch (error) {
    console.error('Cleanup Cron error:', error);
    return res.status(500).json({ error: error.message });
  }
}

import { createClient } from '@supabase/supabase-js';
import { JWT } from 'google-auth-library';

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

async function getAccessToken() {
  let envVar = process.env.FIREBASE_SERVICE_ACCOUNT;
  if (!envVar) {
    throw new Error('FIREBASE_SERVICE_ACCOUNT variable is empty or not set in Vercel.');
  }

  let serviceAccount;
  try {
    // Tenta o parse normal
    serviceAccount = JSON.parse(envVar);
    // Se o resultado for uma string, significa que estava double-stringified (comum no Windows/Vercel)
    if (typeof serviceAccount === 'string') {
      serviceAccount = JSON.parse(serviceAccount);
    }
  } catch (e) {
    throw new Error('FIREBASE_SERVICE_ACCOUNT is not a valid JSON. Error: ' + e.message);
  }

  const privateKey = serviceAccount.private_key || serviceAccount.privateKey;
  const clientEmail = serviceAccount.client_email || serviceAccount.clientEmail;

  if (!privateKey || !clientEmail) {
    throw new Error(`Missing fields in Service Account JSON. Keys found: ${Object.keys(serviceAccount).join(', ')}`);
  }

  // Garantir que a chave tenha o formato correto (newlines reais em vez de \n literais)
  const formattedKey = privateKey.includes('\\n') 
    ? privateKey.replace(/\\n/g, '\n') 
    : privateKey;

  const jwtClient = new JWT({
    email: clientEmail,
    key: formattedKey,
    scopes: ['https://www.googleapis.com/auth/firebase.messaging']
  });

  const tokens = await jwtClient.authorize();
  return tokens.access_token;
}

export default async function handler(req, res) {
  // Verificação de segredo para evitar disparos externos maliciosos
  if (req.headers.authorization !== `Bearer ${process.env.CRON_SECRET}`) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const today = new Date().toISOString().split('T')[0];
    // Normalizar para YYYY-MM-DD
    const in7Days = new Date(new Date().setDate(new Date().getDate() + 7)).toISOString().split('T')[0];
    const in1Day = new Date(new Date().setDate(new Date().getDate() + 1)).toISOString().split('T')[0];

    console.log(`Checking rentals expiring on ${today}, ${in7Days} and ${in1Day}`);

    // 1. Buscar contratos vencendo em 7 ou 1 dia
    // Filtramos apenas os que estão 'ATIVA' (id_status = 1)
    const { data: rentals, error: rentalError } = await supabase
      .from('t_locacao')
      .select('id_usuario, id_armario, dt_termino')
      .in('dt_termino', [today, in7Days, in1Day])
      .eq('id_status', 1);

    if (rentalError) throw rentalError;

    if (!rentals || rentals.length === 0) {
      return res.status(200).json({ message: 'No expiring rentals found today.' });
    }

    // 1.1 Buscar detalhes dos armários (número/código)
    const lockerIds = [...new Set(rentals.map(r => r.id_armario))];
    const { data: lockers, error: lockerError } = await supabase
      .from('t_armario')
      .select('id_armario, cd_armario')
      .in('id_armario', lockerIds);

    if (lockerError) console.error('Error fetching lockers:', lockerError);

    // 2. Coletar e-mails dos usuários afetados
    const userIds = [...new Set(rentals.map(r => r.id_usuario))];
    const { data: users, error: userError } = await supabase
      .from('t_usuario')
      .select('id_usuario, dc_email')
      .in('id_usuario', userIds);

    if (userError) throw userError;

    const userEmails = users.map(u => u.dc_email).filter(Boolean);

    // 3. Buscar tokens FCM por e-mail
    const { data: tokens, error: tokenError } = await supabase
      .from('t_fcm_tokens')
      .select('dc_email, token')
      .in('dc_email', userEmails);

    if (tokenError) throw tokenError;

    if (!tokens || tokens.length === 0) {
      return res.status(200).json({ message: 'Found expiring rentals but no FCM tokens registered.' });
    }

    // 3. Obter Access Token do Firebase
    const accessToken = await getAccessToken();
    const projectId = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT).project_id;

    // 4. Enviar notificações
    const results = [];
    for (const rental of rentals) {
      // Encontrar o e-mail do usuário dono dessa locação
      const userObj = users.find(u => u.id_usuario === rental.id_usuario);
      if (!userObj?.dc_email) continue;

      const userTokens = tokens.filter(t => t.dc_email === userObj.dc_email);
      const lockerObj = lockers?.find(l => l.id_armario === rental.id_armario);
      const lockerDisplay = lockerObj?.cd_armario || rental.id_armario;

      let daysLeft = 0;
      if (rental.dt_termino === in7Days) daysLeft = 7;
      else if (rental.dt_termino === in1Day) daysLeft = 1;

      const notificationBody = daysLeft === 0 
        ? `Seu contrato do armário #${lockerDisplay} venceu hoje!` 
        : `Sua locação do armário #${lockerDisplay} vence em ${daysLeft} dia(s).`;

      // 4.1 Salvar no histórico (t_notificacoes) para o sininho
      // Fazemos isso independente de ter tokens, para aparecer no dashboard
      try {
        await supabase
          .from('t_notificacao')
          .insert({
            id_usuario: rental.id_usuario,
            dc_titulo: 'Vencimento de Armário 📦',
            dc_mensagem: notificationBody,
            is_lida: false
          });
      } catch (dbErr) {
        console.error('Error saving notification to history:', dbErr);
      }

      for (const t of userTokens) {
        try {
          const fcmResponse = await fetch(
            `https://fcm.googleapis.com/v1/projects/${projectId}/messages:send`,
            {
              method: 'POST',
              headers: {
                'Authorization': `Bearer ${accessToken}`,
                'Content-Type': 'application/json'
              },
              body: JSON.stringify({
                message: {
                  token: t.token,
                  data: {
                    title: 'Vencimento de Armário 📦',
                    body: notificationBody,
                    icon: 'https://camubox.com/pwa-icon.png',
                    badge: 'https://camubox.com/badge-72.png',
                    url: 'https://camubox.com/dashboard/my-locker'
                  },
                  android: {
                    priority: 'high'
                  },
                  webpush: {
                    headers: {
                      Urgency: 'high'
                    },
                    fcm_options: {
                      link: 'https://camubox.com/dashboard/my-locker'
                    }
                  }
                }
              })
            }
          );

          const resultData = await fcmResponse.json();
          results.push({ 
            user: rental.id_usuario, 
            status: fcmResponse.ok ? 'success' : 'failed',
            details: resultData 
          });
        } catch (err) {
          results.push({ user: rental.id_usuario, status: 'error', error: err.message });
        }
      }
    }

    return res.status(200).json({ 
      summary: `Processed ${rentals.length} rentals, sent to ${results.filter(r => r.status === 'success').length} devices.`,
      results 
    });
  } catch (error) {
    console.error('Cron error:', error);
    return res.status(500).json({ error: error.message });
  }
}

import { createClient } from '@supabase/supabase-js';
import { JWT } from 'google-auth-library';

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

async function getAccessToken() {
  const envVar = process.env.FIREBASE_SERVICE_ACCOUNT;
  if (!envVar) throw new Error('Missing FIREBASE_SERVICE_ACCOUNT');

  let serviceAccount = JSON.parse(envVar);
  if (typeof serviceAccount === 'string') serviceAccount = JSON.parse(serviceAccount);

  const privateKey = (serviceAccount.private_key || serviceAccount.privateKey).replace(/\\n/g, '\n');
  const clientEmail = serviceAccount.client_email || serviceAccount.clientEmail;

  const jwtClient = new JWT({
    email: clientEmail,
    key: privateKey,
    scopes: ['https://www.googleapis.com/auth/firebase.messaging']
  });

  const tokens = await jwtClient.authorize();
  return tokens.access_token;
}

export default async function handler(req, res) {
  // Only allow POST with proper auth
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });
  if (req.headers.authorization !== `Bearer ${process.env.CRON_SECRET}`) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const { record } = req.body; // Supabase Webhook sends the new row in 'record'
    if (!record || !record.id_usuario) {
      return res.status(400).json({ error: 'Invalid record data' });
    }

    // 1. Get user email
    const { data: user, error: userError } = await supabase
      .from('t_usuario')
      .select('dc_email')
      .eq('id_usuario', record.id_usuario)
      .single();

    if (userError || !user?.dc_email) {
      return res.status(404).json({ error: 'User email not found' });
    }

    // 2. Get FCM tokens
    const { data: tokens, error: tokenError } = await supabase
      .from('t_fcm_tokens')
      .select('token')
      .eq('dc_email', user.dc_email);

    if (tokenError || !tokens || tokens.length === 0) {
      return res.status(200).json({ message: 'No FCM tokens for this user' });
    }

    // 3. Prepare FCM
    const accessToken = await getAccessToken();
    const serviceAccount = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT);
    const projectId = (typeof serviceAccount === 'string' ? JSON.parse(serviceAccount) : serviceAccount).project_id;

    // 4. Send to all registered devices
    const results = [];
    for (const t of tokens) {
      try {
        const fcmResponse = await fetch(
          `https://fcm.googleapis.com/v1/projects/${projectId}/messages:send`,
          {
            method: 'POST',
            headers: {
              'Authorization': `Bearer ${accessToken}`,
              'Content-Type': 'application/json'
            },
            body: JSON.stringify({
              message: {
                token: t.token,
                data: {
                  title: record.dc_titulo || 'CAMUBOX 📦',
                  body: record.dc_mensagem,
                  icon: 'https://camubox.com/pwa-icon.png',
                  badge: 'https://camubox.com/badge-72.png',
                  url: record.tp_entidade === 'armario' 
                    ? `https://camubox.com/dashboard/locker?openLockerId=${record.id_entidade}`
                    : 'https://camubox.com/dashboard/locker',
                  lockerId: record.tp_entidade === 'armario' ? record.id_entidade : undefined
                },
                android: {
                  priority: 'high'
                },
                webpush: {
                  headers: {
                    Urgency: 'high'
                  },
                  fcm_options: {
                    link: record.tp_entidade === 'armario' 
                      ? `https://camubox.com/dashboard/locker?openLockerId=${record.id_entidade}`
                      : 'https://camubox.com/dashboard/locker'
                  }
                }
              }
            })
          }
        );
        const resData = await fcmResponse.json();
        results.push({ token: t.token.substring(0, 10) + '...', status: fcmResponse.status, details: resData });
      } catch (err) {
        results.push({ token: '...', error: err.message });
      }
    }

    return res.status(200).json({ success: true, results });
  } catch (error) {
    console.error('[PUSH ERROR]', error);
    return res.status(500).json({ error: error.message });
  }
}

import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { email, token } = req.body;

  if (!email || !token) {
    return res.status(400).json({ error: 'Missing email or token' });
  }

  try {
    // Upsert token by email
    const { data, error } = await supabase
      .from('t_fcm_tokens')
      .upsert(
        { dc_email: email, token: token },
        { onConflict: 'dc_email' }
      )
      .select();

    if (error) throw error;

    return res.status(200).json({ success: true, data });
  } catch (error) {
    console.error('[API] Error upserting FCM token:', error);
    return res.status(500).json({ error: error.message });
  }
}

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const { correlationID, value, comment, customer } = req.body;
  const appId = process.env.WOOVI_APP_ID;

  if (!appId) {
    return res.status(500).json({ error: 'WOOVI_APP_ID not configured' });
  }

  try {
    const response = await fetch('https://api.woovi.com/api/v1/charge', {
      method: 'POST',
      headers: {
        'Authorization': appId,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        correlationID,
        value,
        comment,
        customer
      })
    });

    const data = await response.json();

    if (!response.ok) {
      return res.status(response.status).json(data);
    }

    return res.status(200).json(data);
  } catch (error) {
    console.error('Error creating Woovi charge:', error);
    return res.status(500).json({ error: 'Failed to create Pix charge' });
  }
}

import { createClient } from '@supabase/supabase-js';

export default async function handler(req, res) {
  // 1. Headers de CORS para permitir que a Woovi acesse
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader('Access-Control-Allow-Headers', 'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version, x-openpix-signature, x-webhook-signature');

  // 2. Responde OK imediatamente para requisições de teste (OPTIONS)
  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  console.log(`>>> WEBHOOK CONTACT: ${req.method} | Body:`, JSON.stringify(req.body));

  // Resposta para o navegador (GET)
  if (req.method === 'GET') {
     return res.status(200).send('Webhook Camubox está Ativo e Blindado!');
  }

  const body = req.body || {};
  const event = body.event || body.evento;

  console.log(`>>> WEBHOOK [${req.method}]: Event=${event} | Body:`, JSON.stringify(body));

  // 3. Resposta para o Teste da Woovi (Essencial para validação)
  // Formato exato que funciona no Bus-Manager
  if (req.method === 'POST') {
    if (event === 'teste_webhook' || !event || Object.keys(body).length === 0) {
       console.log('✅ Connectivity Test / Validation Received');
       return res.status(200).json({ received: true, message: 'Test success' });
    }
  }

  // 4. Lógica de Confirmação de Pagamento
  if (event === 'OPENPIX:CHARGE_COMPLETED' || event === 'CHARGE_COMPLETED') {
    try {
      const charge = body.charge || body.cobranca;
      const correlationID = charge?.correlationID || body.correlationID;

      if (correlationID) {
        const supabase = createClient(
          process.env.SUPABASE_URL,
          process.env.SUPABASE_SERVICE_ROLE_KEY
        );

        await supabase
          .from('t_locacao')
          .update({ id_status: 1 })
          .eq('id_locacao', correlationID);

        console.log(`✅ Pagamento Confirmado: ${correlationID}`);
      }
    } catch (err) {
      console.error('❌ Erro no processamento:', err);
    }
  }

  return res.status(200).json({ received: true });
}

import { createClient } from '@supabase/supabase-js';
import { readFileSync } from 'fs';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const envPath = join(__dirname, '.env.local');

let supabaseUrl = '';
let supabaseKey = '';

try {
    const envContent = readFileSync(envPath, 'utf8');
    const lines = envContent.split('\n');
    lines.forEach(line => {
        const parts = line.split('=');
        if (parts.length >= 2) {
            const key = parts[0].trim();
            const value = parts.slice(1).join('=').trim().replace(/"/g, '');
            if (key === 'SUPABASE_URL') supabaseUrl = value;
            if (key === 'SUPABASE_SERVICE_ROLE_KEY') supabaseKey = value;
        }
    });
} catch (e) {}

const supabase = createClient(supabaseUrl, supabaseKey);

