import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

import {
    CheckCircle,
    Clock,
    Wrench,
    Heart,
    LayoutGrid,
    ClipboardCheck
} from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import './AdminHome.css';

const CountUp = ({ end, duration = 1500 }) => {
    const [count, setCount] = useState(0);

    useEffect(() => {
        let startTime = null;
        let animationFrameId;

        const animate = (timestamp) => {
            if (!startTime) startTime = timestamp;
            const progress = Math.min((timestamp - startTime) / duration, 1);

            // Cubic ease-out for smooth deceleration
            const easing = 1 - Math.pow(1 - progress, 3);
            const currentCount = Math.floor(easing * end);

            setCount(currentCount);

            if (progress < 1) {
                animationFrameId = requestAnimationFrame(animate);
            }
        };

        animationFrameId = requestAnimationFrame(animate);
        return () => cancelAnimationFrame(animationFrameId);
    }, [end, duration]);

    return <>{count.toLocaleString()}</>;
};

const AdminHome = () => {
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);
    const [stats, setStats] = useState([
        { label: 'Total de armários', value: 0, icon: <div className="locker-icon-standard" />, color: 'var(--primary)', key: 'total' },
        { label: 'Disponíveis', value: 0, icon: <LayoutGrid />, color: '#10b981', key: 'disponivel' },
        { label: 'Em uso', value: 0, icon: <CheckCircle />, color: '#6366f1', key: 'em-uso' },
        { label: 'Vistoria', value: 0, icon: <Clock />, color: '#f59e0b', key: 'vistoria' },
        { label: 'Manutenção', value: 0, icon: <Wrench />, color: '#94a3b8', key: 'manutencao' },
        { label: 'Gratuitos', value: 0, icon: <Heart />, color: '#8b5cf6', key: 'gratuito' },
    ]);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            try {
                const { data, error } = await dbService.lockers.getAll();
                if (!error && data) {
                    const normalizeStatus = (str) => {
                        if (!str) return 'disponivel';
                        const normalized = str.normalize("NFD")
                            .replace(/[\u0300-\u036f]/g, "")
                            .toLowerCase()
                            .trim()
                            .replace(/\s+/g, '-');

                        if (normalized === 'ocupado') return 'em-uso';
                        return normalized;
                    };

                    const uniqueMap = new Map();
                    const counts = {
                        total: 0,
                        disponivel: 0,
                        'em-uso': 0,
                        'vistoria': 0,
                        manutencao: 0,
                        gratuito: 0
                    };

                    data.forEach(l => {
                        if (l.id_armario && !uniqueMap.has(l.id_armario)) {
                            const status = normalizeStatus(l.situacao || l.dc_status || 'disponivel');
                            uniqueMap.set(l.id_armario, true);

                            counts.total++;
                            if (counts.hasOwnProperty(status)) {
                                counts[status]++;
                            }
                        }
                    });

                    setStats(prev => prev.map(s => ({
                        ...s,
                        value: counts[s.key] !== undefined ? counts[s.key] : (s.key === 'total' ? counts.total : 0)
                    })));
                }
            } catch (err) {
                console.error('[FETCH ERROR]', err);
            } finally {
                setIsLoading(false);
            }
        };
        fetchData();
    }, []);

    const quickActions = [
        { label: 'Ver contratos', icon: <ClipboardCheck size={20} />, color: '#6366f1', path: '/dashboard/admin/contracts' },
        { label: 'Realizar vistoria', icon: <Clock size={20} />, color: '#f59e0b', path: '/dashboard/admin/inspections' },
        { label: 'Pendências', icon: <Wrench size={20} />, color: '#94a3b8', path: '/dashboard/admin/inspections' },
    ];

    return (
        <div className="admin-home premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>Visão Geral</h1>
                    <p>Status atual do sistema CAMUBOX.</p>
                </div>
            </header>

            {/* Stats Cards Row */}
            <div className="stats-grid-6">
                {stats.map((stat, i) => (
                    <div key={i} className="mini-stat-card card">
                        <div className="mini-stat-icon" style={{ backgroundColor: stat.color + '10', color: stat.color }}>
                            {stat.icon}
                        </div>
                        <div className="mini-stat-content">
                            <p className="mini-stat-label">{stat.label}</p>
                            <h3 className="mini-stat-value">
                                {isLoading ? (
                                    <span className="loading-dots">...</span>
                                ) : (
                                    <CountUp end={stat.value} />
                                )}
                            </h3>
                        </div>
                    </div>
                ))}
            </div>

            <section className="dashboard-section card">
                <h3 className="section-title">Ações Rápidas</h3>
                <div className="actions-grid-simple">
                    {quickActions.map((action, i) => (
                        <button 
                            key={i} 
                            className="action-tile-large" 
                            onClick={() => navigate(action.path)}
                        >
                            <div className="action-icon" style={{ backgroundColor: action.color + '10', color: action.color }}>
                                {action.icon}
                            </div>
                            <span>{action.label}</span>
                        </button>
                    ))}
                </div>
            </section>
        </div>
    );
};

export default AdminHome;

import { useState, useEffect } from 'react';
import { dbService } from '../services/supabaseClient';
import {
    Save,
    Shield,
    FileText,
    DollarSign,
    Settings as SettingsIcon,
    Plus,
    Trash2,
    AlertCircle,
    AlertTriangle,
    CheckCircle2,
    XCircle
} from 'lucide-react';
import { authService } from '../services/supabaseClient';
import './AdminSettings.css';

const AdminSettings = () => {
    const [config, setConfig] = useState({
        vl_pequeno_semestral: 0,
        vl_pequeno_anual: 0,
        vl_grande_semestral: 0,
        vl_grande_anual: 0,
        vl_taxa_troca: 20,
        nm_texto_contrato: ''
    });

    const [admins, setAdmins] = useState([]);
    const [newAdminEmail, setNewAdminEmail] = useState('');
    const [isLoadingAdmins, setIsLoadingAdmins] = useState(false);

    const [isLoading, setIsLoading] = useState(true);

    // Modal State
    const [modalConfig, setModalConfig] = useState({ 
        isOpen: false, 
        title: '', 
        message: '', 
        type: 'confirm', 
        onConfirm: null 
    });

    const showModal = (config) => {
        setModalConfig({
            isOpen: true,
            title: config.title || 'Confirmação',
            message: config.message || '',
            type: config.type || 'confirm',
            onConfirm: config.onConfirm || null
        });
    };

    const closeModal = () => {
        setModalConfig(prev => ({ ...prev, isOpen: false }));
    };

    const fetchAdmins = async () => {
        setIsLoadingAdmins(true);
        const { data, error } = await dbService.users.getAdmins();
        if (!error && data) {
            setAdmins(data.map(u => ({
                name: u.nm_usuario || 'Usuário',
                email: u.dc_email,
                role: 'Admin', // Default role for now
                id_usuario: u.id_usuario
            })));
        }
        setIsLoadingAdmins(false);
    };

    useEffect(() => {
        const fetchConfig = async () => {
            setIsLoading(true);
            const { data, error } = await dbService.settings.get();
            if (!error && data) {
                setConfig(prev => ({ ...prev, ...data }));
            }
            setIsLoading(false);
        };

        fetchConfig();
        fetchAdmins();
    }, []);

    const handleAddAdmin = async () => {
        const email = newAdminEmail.trim();
        if (!email) return;

        // Validar formato de e-mail
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email)) {
            showModal({
                title: 'E-mail Inválido',
                message: 'Por favor, insira um endereço de e-mail válido para continuar.',
                type: 'error'
            });
            return;
        }

        setIsLoadingAdmins(true);
        try {
            // 1. Primeiro vamos verificar se o usuário existe no sistema
            const { data: user, error: fetchError } = await dbService.users.getByEmail(email);
            
            if (fetchError || !user) {
                showModal({
                    title: 'Usuário não Encontrado',
                    message: `O e-mail ${email} ainda não está cadastrado no sistema. O usuário precisa fazer login pelo menos uma vez antes de ser promovido a admin.`,
                    type: 'error'
                });
                return;
            }

            // 2. Se existis, atualiza o status
            const { error: updateError } = await dbService.users.updateAdminStatus(email, true);
            
            if (!updateError) {
                setNewAdminEmail('');
                await fetchAdmins();
                showModal({
                    title: 'Sucesso!',
                    message: 'Novo administrador adicionado com sucesso.',
                    type: 'success'
                });
            } else {
                throw updateError;
            }
        } catch (err) {
            showModal({
                title: 'Erro',
                message: 'Não foi possível adicionar o administrador: ' + err.message,
                type: 'error'
            });
        } finally {
            setIsLoadingAdmins(false);
        }
    };

    const handleDeleteAdmin = async (email) => {
        showModal({
            title: 'Confirmar Remoção',
            message: `Tem certeza que deseja remover o acesso administrativo de ${email}?`,
            type: 'confirm',
            onConfirm: async () => {
                setIsLoadingAdmins(true);
                try {
                    const { error } = await dbService.users.updateAdminStatus(email, false);
                    if (!error) {
                        setAdmins(prev => prev.filter(a => a.email !== email));
                        showModal({
                            title: 'Sucesso!',
                            message: 'Acesso administrativo removido com sucesso.',
                            type: 'success'
                        });
                    } else {
                        throw error;
                    }
                } catch (err) {
                    showModal({
                        title: 'Erro',
                        message: 'Erro ao remover acesso: ' + err.message,
                        type: 'error'
                    });
                } finally {
                    setIsLoadingAdmins(false);
                }
            }
        });
    };

    const handleSave = async (sectionLabel) => {
        setIsLoading(true);
        const { error } = await dbService.settings.update(config);
        if (!error) {
            showModal({
                title: 'Sucesso!',
                message: `Configurações de ${sectionLabel} salvas com sucesso!`,
                type: 'success'
            });
        } else {
            showModal({
                title: 'Erro ao Salvar',
                message: `Erro ao salvar: ${error.message}`,
                type: 'error'
            });
        }
        setIsLoading(false);
    };

    const updateConfig = (field, value) => {
        setConfig(prev => ({ ...prev, [field]: value }));
    };

    return (
        <div className="admin-settings-container">
            <header className="page-header">
                <div className="header-text">
                    <h1>Configurações do Sistema</h1>
                    <p>Controle de taxas, regras de negócio e acessos administrativos.</p>
                </div>
            </header>

            {isLoading ? (
                <div className="loading-state-wrapper">
                    <div className="loading-spinner"></div>
                    <span>Sincronizando configurações...</span>
                </div>
            ) : (
                <div className="settings-modern-grid">
                    {/* CARD 1: Valores de Locação */}
                    <section className="settings-modern-card glass">
                        <div className="card-header-premium">
                            <div className="header-title-bundle">
                                <span className="icon-wrapper gold">
                                    <DollarSign size={20} />
                                </span>
                                <h3>Valores de Locação</h3>
                            </div>
                        </div>
                        <div className="card-content-premium">
                            <div className="settings-input-row">
                                <div className="settings-field">
                                    <label>Armário Pequeno (Semestral)</label>
                                    <div className="premium-input-box">
                                        <span className="currency">R$</span>
                                        <input type="number" value={config.vl_pequeno_semestral} onChange={e => updateConfig('vl_pequeno_semestral', e.target.value)} />
                                    </div>
                                </div>
                                <div className="settings-field">
                                    <label>Armário Pequeno (Anual)</label>
                                    <div className="premium-input-box">
                                        <span className="currency">R$</span>
                                        <input type="number" value={config.vl_pequeno_anual} onChange={e => updateConfig('vl_pequeno_anual', e.target.value)} />
                                    </div>
                                </div>
                            </div>
                            <div className="settings-input-row">
                                <div className="settings-field">
                                    <label>Armário Grande (Semestral)</label>
                                    <div className="premium-input-box">
                                        <span className="currency">R$</span>
                                        <input type="number" value={config.vl_grande_semestral} onChange={e => updateConfig('vl_grande_semestral', e.target.value)} />
                                    </div>
                                </div>
                                <div className="settings-field">
                                    <label>Armário Grande (Anual)</label>
                                    <div className="premium-input-box">
                                        <span className="currency">R$</span>
                                        <input type="number" value={config.vl_grande_anual} onChange={e => updateConfig('vl_grande_anual', e.target.value)} />
                                    </div>
                                </div>
                            </div>
                            <div className="settings-field">
                                <label>Taxa de Troca de Armário</label>
                                <div className="premium-input-box">
                                    <span className="currency">R$</span>
                                    <input type="number" value={config.vl_taxa_troca} onChange={e => updateConfig('vl_taxa_troca', e.target.value)} />
                                </div>
                            </div>
                            <button className="premium-save-btn" onClick={() => handleSave('Valores')}>
                                <Save size={18} />
                                <span>Salvar Valores</span>
                            </button>
                        </div>
                               </section>

                    {/* CARD 4: Administradores */}
                    <section className="settings-modern-card glass">
                        <div className="card-header-premium">
                            <div className="header-title-bundle">
                                <span className="icon-wrapper primary">
                                    <Shield size={20} />
                                </span>
                                <h3>Equipe Administrativa</h3>
                            </div>
                        </div>
                        <div className="card-content-premium">
                            <div className="modern-admin-list">

                                    {isLoadingAdmins ? (
                                        <div 
                                            className="loading-admins-state"
                                        >
                                            <div className="spinner-mini-admin"></div>
                                            <span>Sincronizando equipe...</span>
                                        </div>
                                    ) : admins.length === 0 ? (
                                        <div 
                                            className="empty-admin-list-premium"
                                        >
                                            <div className="empty-icon-shield">
                                                <Shield size={32} />
                                            </div>
                                            <p>Nenhum administrador cadastrado.</p>
                                        </div>
                                    ) : (
                                        admins.map((admin) => (
                                            <div 
                                                key={admin.email}
                                                className="modern-admin-item-premium"
                                            >
                                                <div className="admin-avatar-premium">
                                                    {admin.name.charAt(0)}
                                                </div>
                                                <div className="admin-info-bundle">
                                                    <div className="admin-name-meta">
                                                        <strong>{admin.name}</strong>
                                                        <span className="admin-badge">Admin</span>
                                                    </div>
                                                    <span className="admin-email-secondary">{admin.email}</span>
                                                </div>
                                                <button 
                                                    className="remove-admin-control" 
