    XSquare,
    Wrench,
    Search,
    Filter,
    Loader2
} from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import './LockerInspection.css';

const LockerInspection = () => {
    const [inspections, setInspections] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedFloor, setSelectedFloor] = useState('all');
    const [activeTab, setActiveTab] = useState('vistoria'); // 'vistoria' or 'manutencao'

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [lockersRes, usersRes] = await Promise.all([
                dbService.lockers.getAll(),
                dbService.users.getAll()
            ]);

            const userMap = (usersRes.data || []).reduce((acc, u) => ({ ...acc, [u.id_usuario]: u.nm_usuario }), {});

            if (!lockersRes.error && lockersRes.data) {
                const targetLockerRecords = lockersRes.data.filter(l => {
                    const status = (l.situacao || l.dc_status || '').normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
                    return status === 'vistoria' || status === 'aguardando-vistoria' || status === 'manutencao' || status === 'manutenção';
                });

                const lockerIds = targetLockerRecords.map(l => l.id_armario);

                // Fetch recent rentals for these specific lockers from t_locacao
                const rentalsRes = await dbService.rentals.getHistoryByLockers(lockerIds);
                const rentalsByLocker = (rentalsRes.data || []).reduce((acc, r) => {
                    // First entry for each locker will be the most recent due to order by dt_termino desc
                    if (!acc[r.id_armario]) acc[r.id_armario] = r;
                    return acc;
                }, {});

                const processedLockers = targetLockerRecords.map(l => {
                    const lastRental = rentalsByLocker[l.id_armario];
                    const rawStatus = (l.situacao || l.dc_status || '').normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
                    const category = (rawStatus === 'manutencao' || rawStatus === 'manutenção') ? 'manutencao' : 'vistoria';
                    
                    return {
                        id: (l.nr_armario || l.cd_armario || '').toString().padStart(3, '0'),
                        dbId: l.id_armario,
                        floor: l.nm_local || l.dc_andar || 'Térreo',
                        category,
                        prevUser: lastRental ? (userMap[lastRental.id_usuario] || `ID: ${lastRental.id_usuario}`) : 'Sem locação prévia',
                        dueDate: lastRental?.dt_termino ? (function (dt) {
                            const date = new Date(dt);
                            date.setMinutes(date.getMinutes() + date.getTimezoneOffset());
                            return date.toLocaleDateString();
                        })(lastRental.dt_termino) : 'N/A'
                    };
                });
                setInspections(processedLockers);
            }
        } catch (err) {
            console.error('[FETCH INSPECTIONS ERROR]', err);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const uniqueFloors = ['all', ...new Set(inspections.filter(i => i.category === activeTab).map(i => i.floor))];

    const filteredInspections = inspections.filter(item => {
        const matchesTab = item.category === activeTab;
        const matchesSearch = item.id.includes(searchTerm);
        const matchesFloor = selectedFloor === 'all' || item.floor === selectedFloor;
        return matchesTab && matchesSearch && matchesFloor;
    });

    const handleAction = async (dbId, action) => {
        try {
            if (action === 'confirm') {
                await dbService.lockers.updateStatus(dbId, 'DISPONIVEL');
                await fetchData();
            } else {
                await dbService.lockers.updateStatus(dbId, 'MANUTENCAO');
                await fetchData();
            }
        } catch (error) {
            console.error('Error in inspection action:', error);
        }
    };

    return (
        <div className="locker-inspection-page premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>{activeTab === 'vistoria' ? 'Vistorias' : 'Manutenção'}</h1>
                    <p>
                        {activeTab === 'vistoria' 
                            ? 'Fila de liberação técnica de armários após o fim do contrato.' 
                            : 'Armários atualmente bloqueados para reparos mecânicos ou limpeza profunda.'}
                    </p>
                </div>
            </header>

            <div className="inspection-tabs" style={{ marginBottom: '1.5rem', width: '100%', display: 'flex', gap: '24px', borderBottom: '1px solid #e2e8f0', paddingBottom: '0' }}>
                <button 
                    className={activeTab === 'vistoria' ? 'active' : ''} 
                    onClick={() => setActiveTab('vistoria')}
                    style={{ 
                        padding: '12px 16px', 
                        border: 'none', 
                        background: 'transparent', 
                        color: activeTab === 'vistoria' ? '#2563eb' : '#64748b', 
                        fontWeight: activeTab === 'vistoria' ? 600 : 500, 
                        borderBottom: activeTab === 'vistoria' ? '2px solid #2563eb' : '2px solid transparent',
                        marginBottom: '-1px',
                        transition: 'all 0.2s',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '8px',
                        cursor: 'pointer',
                        fontSize: '0.95rem'
                    }}
                >
                    <ClipboardCheck size={18} />
                    <span className="hide-on-mobile">Vistoria</span>
                </button>
                <button 
                    className={activeTab === 'manutencao' ? 'active' : ''} 
                    onClick={() => setActiveTab('manutencao')}
                    style={{ 
                        padding: '12px 16px', 
                        border: 'none', 
                        background: 'transparent', 
                        color: activeTab === 'manutencao' ? '#2563eb' : '#64748b', 
                        fontWeight: activeTab === 'manutencao' ? 600 : 500, 
                        borderBottom: activeTab === 'manutencao' ? '2px solid #2563eb' : '2px solid transparent',
                        marginBottom: '-1px',
                        transition: 'all 0.2s',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '8px',
                        cursor: 'pointer',
                        fontSize: '0.95rem'
                    }}
                >
                    <Wrench size={18} />
                    <span className="hide-on-mobile">Manutenção</span>
                </button>
            </div>

            <div className="filter-bar">
                <div className="search-box">
                    <Search size={18} className="search-icon" />
                    <input
                        type="text"
                        placeholder="Pesquisar armário..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        autoComplete="off"
                        spellCheck="false"
                        autoCorrect="off"
                        autoCapitalize="off"
                    />
                </div>
                <div className="filter-group">
                    <Filter size={18} className="filter-icon" />
                    <select
                        value={selectedFloor}
                        onChange={(e) => setSelectedFloor(e.target.value)}
                    >
                        {uniqueFloors.map(floor => (
                            <option key={floor} value={floor}>
                                {floor === 'all' ? 'Todos os andares' : floor}
                            </option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="inspection-container card">
                {isLoading ? (
                    <div className="loading-state-matrix" style={{ padding: '40px', textAlign: 'center' }}>
                        <Loader2 className="spinner" size={40} />
                        <p>Carregando vistorias...</p>
                    </div>
                ) : (
                    <table className="inspection-table-simple">
                        <thead>
                            <tr>
                                <th>Armário</th>
                                <th>Responsável Anterior</th>
                                <th>{activeTab === 'vistoria' ? 'Vencimento' : 'Data da Ocorrência'}</th>
                                <th className="actions-cell text-right">Ações</th>
                            </tr>
                        </thead>
                            <tbody>
                                {filteredInspections.map((item, index) => (
                                    <tr 
                                        key={item.dbId}
                                    >
                                    <td className="col-armario">
                                        <div className="unified-locker-badge">
                                            <span className="locker-id-part">{item.id}</span>
                                            <div className="floor-part">
                                                <span>{item.floor}</span>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="col-user">
                                        <div className="info-item">
                                            <UserIcon size={14} className="icon-sub" />
                                            <span className="txt-main">{item.prevUser}</span>
                                        </div>
                                    </td>
                                    <td className="col-date">
                                        <div className="info-item">
                                            <Calendar size={14} className="icon-sub" />
                                            <span className="txt-sub">{item.dueDate}</span>
                                        </div>
                                    </td>
                                    <td className="actions-cell">
                                        {activeTab === 'vistoria' ? (
                                            <div className="action-row-compact">
                                                <button
                                                    className="btn-compact-success"
                                                    onClick={() => handleAction(item.dbId, 'confirm')}
                                                >
                                                    <CheckCircle2 size={16} />
                                                    <span>Liberar</span>
                                                </button>
                                                <button
                                                    className="btn-compact-warning"
                                                    onClick={() => handleAction(item.dbId, 'problem')}
                                                >
                                                    <Wrench size={16} />
                                                    <span>Manutenção</span>
                                                </button>
                                            </div>
                                        ) : (
                                            <div className="action-row-compact">
                                                <button
                                                    className="btn-compact-success"
                                                    onClick={() => handleAction(item.dbId, 'confirm')}
                                                >
                                                    <CheckCircle2 size={16} />
                                                    <span>Reparo Concluído</span>
                                                </button>
                                            </div>
                                        )}
                                    </td>
                                    </tr>
                                ))}
                            {filteredInspections.length === 0 && (
                                <tr>
                                    <td colSpan="4" className="empty-state">Nenhum resultado encontrado.</td>
                                </tr>
                            )}
                            </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default LockerInspection;

import { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { IoMdPricetag } from 'react-icons/io';
import {
    QrCode,
    Copy,
    RefreshCcw,
    CheckCircle2,
    Clock,
    XCircle,
    ChevronLeft,
    ArrowRight,
    MapPin
} from 'lucide-react';
import { supabase } from '../services/supabaseClient';
import './PixPayment.css';

const PixPayment = ({ user }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const { state } = location;

    // Status can be: 'generating' -> 'pending' -> 'verifying' -> 'confirmed' -> 'error'
    const [status, setStatus] = useState('generating');
    const [copied, setCopied] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');

    const isExchange = state?.type === 'exchange';
    const exchangeInfo = state?.exchangeInfo;
    const selectedLocker = state?.locker || {
        id: '000',
        size: 'N/A',
        plan: 'semestral',
        priceSem: 0,
        priceAnn: 0
    };

    const isSemestral = selectedLocker.plan?.toLowerCase() === 'semestral';
    const price = isExchange ? 20 : (isSemestral ? selectedLocker.priceSem : selectedLocker.priceAnn);

    const rentalDetails = {
        id: selectedLocker.id,
        contract: isExchange ? 'Taxa de Troca' : (isSemestral ? 'Semestral' : 'Anual'),
        price: `R$ ${price},00`
    };

    const [qrCodeData, setQrCodeData] = useState(null);

    // Gerar cobrança real na Woovi
    useEffect(() => {
        const generatePix = async () => {
            if (!user) return;
            try {
                // 1. Criar o registro da locação no Supabase primeiro para ter o ID
                let correlationID;

                if (isExchange) {
                    correlationID = `${exchangeInfo.rentalId}`;
                } else {
                    const { data: newRental, error: rentalError } = await supabase.from('t_locacao').insert({
                        id_armario: selectedLocker.dbId,
                        id_usuario: user.id_usuario,
                        id_tipo: isSemestral ? 1 : 2,
                        id_status: 3, // Assumindo 3 como Pendente
                        dt_inicio: new Date().toISOString(),
                        dt_termino: isSemestral 
                           ? new Date(new Date().setMonth(new Date().getMonth() + 6)).toISOString()
                           : new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString()
                    }).select().single();

                    if (rentalError) throw rentalError;
                    correlationID = newRental.id_locacao.toString();
                }

                // 2. Chamar nossa API de backend para criar a cobrança na Woovi
                const response = await fetch('/api/woovi/charge', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        correlationID,
                        value: price * 100, // Woovi usa centavos
                        comment: isExchange ? `Troca Armário ${selectedLocker.id}` : `Locação Armário ${selectedLocker.id}`,
                        customer: {
                            name: user.nm_usuario || user.email,
                            email: user.email,
                        }
                    })
                });

                if (!response.ok) {
                    const text = await response.text();
                    throw new Error(`Erro ${response.status}: ${text.substring(0, 50)}...`);
                }

                const data = await response.json();
                setQrCodeData(data.charge);
                setStatus('pending');

                // 3. Opcional: Escutar mudanças no Supabase via Realtime para confirmar automático
                const subscription = supabase
                    .channel('status-update')
                    .on('postgres_changes', { 
                        event: 'UPDATE', 
                        schema: 'public', 
                        table: 't_locacao',
                        filter: `id_locacao=eq.${correlationID}`
                    }, (payload) => {
                        if (payload.new.id_status === 1) {
                            setStatus('confirmed');
                            // Mark waiting list as complete if this was a reserved locker
                            dbService.waitingList.complete(selectedLocker.dbId, user.id_usuario);
                            subscription.unsubscribe();
                        }
                    })
                    .subscribe();

            } catch (err) {
                console.error('Erro Woovi:', err);
                setErrorMsg('Erro ao gerar PIX. Verifique sua conexão ou tente mais tarde.');
                setStatus('error');
            }
        };

        generatePix();
    }, [user]);

    const handleCopy = () => {
        if (qrCodeData?.brCode) {
            navigator.clipboard.writeText(qrCodeData.brCode);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        }
    };

    const handleMockPayment = async () => {
        setStatus('verifying');
        try {
            if (!user) throw new Error('Usuário não logado');

            if (isExchange) {
                // MOCK Exchange logic
                const { data: oldRental } = await supabase.from('t_locacao').select('*').eq('id_locacao', exchangeInfo.rentalId).single();
                if (oldRental) {
                    const historyRecord = { ...oldRental };
                    delete historyRecord.id_locacao;
                    historyRecord.id_status = 2; // Historico
                    historyRecord.dt_termino = new Date().toISOString().split('T')[0];
                    await supabase.from('t_locacao').insert([historyRecord]);
                }
                await supabase.from('t_locacao').update({ id_armario: selectedLocker.dbId }).eq('id_locacao', exchangeInfo.rentalId);
            } else {
                // MOCK Rental logic
                await supabase.from('t_locacao').insert({
                    id_armario: selectedLocker.dbId,
                    id_usuario: user.id_usuario,
                    id_tipo: 1,
                    id_status: 1,
                    dt_inicio: new Date().toISOString(),
                    dt_termino: new Date(new Date().setMonth(new Date().getMonth() + 6)).toISOString()
                });
            }

            // Mark waiting list as complete if this was a reserved locker
            await dbService.waitingList.complete(selectedLocker.dbId, user.id_usuario);

            setStatus('confirmed');
        } catch (error) {
            console.error(error);
            setErrorMsg('Erro ao confirmar pagamento. Tente novamente.');
            setStatus('error');
        }
    };

    return (
        <div className="pix-payment-page premium-theme">
            <header className="page-header">
                <button className="back-btn-premium" onClick={() => navigate(-1)}>
                    <ChevronLeft size={20} />
                </button>
                <div className="header-text">
                    <h1>{isExchange ? 'Pagamento da Taxa de Troca' : 'Finalizar Pagamento'}</h1>
                    <p>{isExchange ? 'Após o pagamento, sua troca será processada instantaneamente.' : 'Sua reserva está garantida enquanto o QR Code for válido.'}</p>
                </div>
            </header>

            <div className="payment-grid-premium">
                {/* Compact Top Summary - Visible on Mobile */}
                <section className="compact-payment-summary">
                    <div className="summary-item">
                        <img src="/lockers.png" alt="Armário" className="locker-picto" />
                        <span>{isExchange ? `Novo Armário #${selectedLocker.id}` : `Armário #${rentalDetails.id}`}</span>
                    </div>
                    {selectedLocker.floor && (
                        <div className="summary-item">
                            <span>{selectedLocker.floor}</span>
                        </div>
                    )}
                    <div className="summary-item">
                        <IoMdPricetag size={18} style={{ color: 'var(--primary)' }} />
                        <span>{rentalDetails.contract}</span>
                    </div>
                    <div className="summary-item price-badge">
                        <span>{rentalDetails.price}</span>
                    </div>
                </section>

                <main className="payment-main-content">
                    <section className="qr-card card">
                        <div className="card-top">
                            <div className={`status-pill ${status}`}>
                                {status === 'generating' && <><RefreshCcw size={14} className="animate-spin" /> <span>Gerando Pix...</span></>}
                                {status === 'pending' && <><Clock size={14} /> <span>Aguardando...</span></>}
                                {status === 'verifying' && <><RefreshCcw size={14} className="animate-spin" /> <span>Analisando Confirmação...</span></>}
                                {status === 'confirmed' && <><CheckCircle2 size={14} /> <span>Pago</span></>}
                                {status === 'error' && <><XCircle size={14} /> <span>Erro</span></>}
                            </div>
                            <div className="timer-text">
                                Expira em: <strong>30:00</strong>
                            </div>
                        </div>

                        <div className="qr-main-container">
                            <div className={`qr-frame ${status === 'confirmed' ? 'paid' : ''}`}>
                                {status === 'generating' ? (
                                    <div className="qr-skeleton animate-pulse" style={{backgroundColor: 'rgba(255,255,255,0.1)', borderRadius: 12}}></div>
                                ) : status === 'error' ? (
                                    <XCircle size={80} color="var(--red-500)" />
                                ) : (
                                    <img src={qrCodeData?.qrCodeImage} alt="QR Code Pix" style={{borderRadius: 8}} />
                                )}

                                {status === 'confirmed' && (
                                    <div className="success-overlay">
                                        <CheckCircle2 size={60} />
                                    </div>
                                )}
                            </div>
                        </div>

                        <p className="qr-instruction">Aponte a câmera do seu aplicativo de banco para o QR Code acima</p>

                        <div className="pix-copy-area">
                            <label>Código Copia e Cola</label>
                            <div className="copy-input-group">
                                <input type="text" value={status === 'generating' ? 'Gerando código...' : (qrCodeData?.brCode || 'Erro ao carregar')} readOnly />
                                <button className={`copy-btn-premium ${copied ? 'success' : ''}`} onClick={handleCopy} disabled={status === 'generating' || !qrCodeData?.brCode}>
                                    {copied ? <CheckCircle2 size={18} /> : <Copy size={18} />}
                                    <span>{copied ? 'Copiado' : 'Copiar'}</span>
                                </button>
                            </div>
                            {errorMsg && <p className="error-message p-sm" style={{color: 'var(--red-500)', marginTop: 8}}>{errorMsg}</p>}
                        </div>
                    </section>
                </main>

                <aside className="payment-sidebar">
                    <div className="order-summary card">
                        <h3>Resumo do {isExchange ? 'Processo' : 'Pedido'}</h3>
                        <div className="order-rows">
                            <div className="order-row">
                                <img src="/lockers.png" alt="" className="nav-img-icon" style={{ opacity: 0.7 }} />
                                <span>{isExchange ? `Novo Armário #${selectedLocker.id}` : `Armário #${rentalDetails.id}`}</span>
                            </div>
                            <div className="order-row">
                                <IoMdPricetag size={20} style={{ color: 'var(--primary)' }} />
                                <span>{rentalDetails.contract}</span>
                            </div>
                        </div>
                        <div className="order-total">
                            <label>Valor Total</label>
                            <span className="price-tag">{rentalDetails.price}</span>
                        </div>
                    </div>

                    <div className="action-stack">
                        {status !== 'confirmed' ? (
                            <>
                                <button
                                    className={`verify-btn-premium ${status === 'verifying' ? 'loading' : ''}`}
                                    onClick={() => setStatus('verifying')}
                                    disabled={status === 'verifying' || status === 'generating'}
                                >
                                    {status === 'verifying' ? 'Verificando...' : 'Já paguei'}
                                </button>
                                <button className="cancel-order-btn" onClick={() => navigate('/dashboard/lockers')}>
                                    Cancelar locação
                                </button>
                            </>
                        ) : (
                            <div className="payment-success-card animate-bounce-in">
                                <div className="success-header">
                                    <CheckCircle2 size={32} />
                                    <h3>{isExchange ? 'Troca Realizada!' : 'Sucesso!'}</h3>
                                </div>
                                <p>{isExchange ? 'Sua troca foi concluída e o novo armário já está ativo.' : 'Sua locação foi confirmada e o armário já está liberado.'}</p>
                                <button className="go-to-lockers-btn" onClick={() => navigate('/dashboard/my-locker')}>
                                    Ver Meus Armários
                                    <ArrowRight size={18} />
                                </button>
                            </div>
                        )}
                    </div>
                </aside>
            </div>
        </div>
    );
};

export default PixPayment;

import { useState, useEffect, useMemo } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    Search,
    MapPin,
    Maximize2,
    Clock,
    CheckCircle2,
    AlertTriangle,
    Wrench,
    ChevronRight,
    Sparkles,
    Loader2,
    X,
    Lock,
    Calendar,
    TrendingDown
} from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import './UserLockerSelection.css';

const UserLockerSelection = ({ user }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const queryParams = new URLSearchParams(location.search);
    const exchangeFor = queryParams.get('exchange_for');
    const exchangeSize = queryParams.get('size');
    const oldLockerId = queryParams.get('old_id');

    const [searchTerm, setSearchTerm] = useState('');
    const [isLoading, setIsLoading] = useState(true);
    const [lockers, setLockers] = useState([]);
    const [selectedLocker, setSelectedLocker] = useState(null);
    const [isPanelOpen, setIsPanelOpen] = useState(false);
    const [filters, setFilters] = useState({
        floorId: 'All',
        sizeId: exchangeSize ? 'All' : 'All', // We will force sizeId if exchanging
        contract: 'Semestral'
    });
    const [lookups, setLookups] = useState({ floors: {}, sizes: {}, statuses: {}, positions: {} });
    const [statusModal, setStatusModal] = useState(null);
    const [waitingListStatus, setWaitingListStatus] = useState(null);
    const [isProcessingWaitingList, setIsProcessingWaitingList] = useState(false);

    useEffect(() => {
        if (exchangeSize) {
            // Find size ID from name if possible or just filter by name in useMemo
        }
    }, [exchangeSize]);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            try {
                // Fetch in parallel
                const [lockersRes, lookupRes, configRes] = await Promise.all([
                    dbService.lockers.getAll(),
                    dbService.lockers.getLookups(),
                    dbService.lockers.getConfig()
                ]);

                if (lookupRes.error) throw lookupRes.error;
                setLookups(lookupRes.data || {});

                if (!lockersRes.error && lockersRes.data) {
                    const config = configRes.data || {};

                    // Normalize status helper
                    const normalizeStatus = (str) => {
                        if (!str) return 'disponivel';
                        const normalized = str.normalize("NFD")
                            .replace(/[\u0300-\u036f]/g, "")
                            .toLowerCase()
                            .trim()
                            .replace(/\s+/g, '-');
                        
                        // Map reservado to a specific string
                        if (normalized.includes('reservado')) return 'reservado';
                        return normalized;
                    };

                    const uniqueMap = new Map();

                    lockersRes.data.forEach(l => {
                        if (l.id_armario && !uniqueMap.has(l.id_armario)) {
                            const rawNr = l.nr_armario || l.cd_armario;
                            const formattedNr = rawNr ? rawNr.toString().padStart(3, '0') : 'N/A';

                            const sizeLabel = l.dc_tamanho || l.nm_tamanho || 'Pequeno';
                            const isLarge = sizeLabel.toLowerCase() === 'grande';

                            uniqueMap.set(l.id_armario, {
                                id: formattedNr,
                                nr: formattedNr,
                                dbId: l.id_armario,
                                localId: l.id_local,
                                sizeId: l.id_tamanho,
                                floor: l.dc_andar || l.nm_local || 'Térreo',
                                size: sizeLabel,
                                position: l.dc_posicao || l.nm_posicao || 'Não definida',
                                status: normalizeStatus(l.situacao || l.dc_status || 'Disponivel'),
                                priceSem: isLarge ? config.vl_grande_semestral : config.vl_pequeno_semestral,
                                priceAnn: isLarge ? config.vl_grande_anual : config.vl_pequeno_anual,
                            });
                        }
                    });

                    const mapped = Array.from(uniqueMap.values());
                    setLockers(mapped);
                }
            } catch (err) {
                console.error('[FETCH ERROR]', err);
            } finally {
                setIsLoading(false);
            }
        };

        fetchData();
    }, []);

    useEffect(() => {
        if (isPanelOpen || statusModal) {
            document.body.classList.add('no-scroll');
        } else {
            document.body.classList.remove('no-scroll');
        }
        return () => {
            document.body.classList.remove('no-scroll');
        };
    }, [isPanelOpen, statusModal]);

    // Check waiting list status when modal opens
    useEffect(() => {
        const checkWaitingList = async () => {
            if (statusModal && user) {
                const { data } = await dbService.waitingList.getStatus(statusModal.dbId, user.id_usuario);
                setWaitingListStatus(data);
            } else {
                setWaitingListStatus(null);
            }
        };
        checkWaitingList();
    }, [statusModal, user]);

    // Deep-linking: Open locker details from URL parameter
    useEffect(() => {
        const lockerIdToOpen = queryParams.get('openLockerId');
        if (lockerIdToOpen && lockers.length > 0 && !statusModal && !isPanelOpen) {
            const locker = lockers.find(l => l.dbId.toString() === lockerIdToOpen.toString());
            if (locker) {
                console.log('[DeepLink] Opening locker:', lockerIdToOpen);
                openLockerDetails(locker);
            }
        }
    }, [lockers, location.search, statusModal, isPanelOpen]);

    const displayLockers = useMemo(() => {
        const fFloorId = filters.floorId;
        const fSizeId = filters.sizeId;
        const fSearch = searchTerm.trim().toLowerCase();

        const selectedFloorName = lookups.floors?.[fFloorId];
        const selectedSizeName = lookups.sizes?.[fSizeId];

        return lockers
            .filter(locker => {
                const matchesSearch = !fSearch || locker.id.toLowerCase().includes(fSearch);

                const matchesFloor = fFloorId === 'All' ||
                    locker.localId?.toString() === fFloorId.toString() ||
                    (selectedFloorName && locker.floor === selectedFloorName);

                // If exchangeMode, force same size
                let matchesSize = fSizeId === 'All' ||
                    locker.sizeId?.toString() === fSizeId.toString() ||
                    (selectedSizeName && locker.size === selectedSizeName);
                
                if (exchangeSize) {
                    matchesSize = locker.size.toLowerCase() === exchangeSize.toLowerCase();
                }

                return matchesSearch && matchesFloor && matchesSize;
            })
            .sort((a, b) => (parseInt(a.nr) || 0) - (parseInt(b.nr) || 0));
    }, [lockers, filters.floorId, filters.sizeId, searchTerm, lookups, exchangeSize]);

    const openLockerDetails = async (locker) => {
        // If locker is reserved, check if it's for this user
        if (locker.status === 'reservado' && user) {
            const { data } = await dbService.waitingList.getStatus(locker.dbId, user.id_usuario);
            // If user is the one who has the reservation (status 2 in queue)
            if (data && data.id_status === 2) {
                setSelectedLocker(locker);
                setIsPanelOpen(true);
                return;
            }
        }

        if (locker.status === 'disponivel') {
            setSelectedLocker(locker);
            setIsPanelOpen(true);
        } else {
            setStatusModal(locker);
        }
    };

    const handleJoinWaitingList = async () => {
        if (!statusModal || !user) return;
        setIsProcessingWaitingList(true);
        try {
            const { error } = await dbService.waitingList.join(statusModal.dbId, user.id_usuario);
            if (error) throw error;
            
            // Refresh status
            const { data } = await dbService.waitingList.getStatus(statusModal.dbId, user.id_usuario);
            setWaitingListStatus(data);
        } catch (err) {
            console.error('[WAITING LIST ERROR]', err);
            alert('Erro ao entrar na fila: ' + (err.message || 'Tente novamente.'));
        } finally {
            setIsProcessingWaitingList(false);
        }
    };

    const getStatusClass = (status) => {
        if (status === 'disponivel') return 'status-available';
        if (status === 'ocupado' || status === 'em-uso') return 'status-occupied';
        if (status === 'vistoria') return 'status-inspection';
        if (status === 'manutencao') return 'status-maintenance';
        if (status === 'reservado') return 'status-reserved';
        return '';
    };

    return (
        <div className="user-selection premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>{exchangeFor ? `Trocar para #${exchangeSize}` : 'Armários Disponíveis'}</h1>
                    <p>{exchangeFor ? `Selecione um novo armário ${exchangeSize.toLowerCase()} para realizar a troca.` : 'Encontre a melhor unidade para seu semestre.'}</p>
                </div>
            </header>

            <section className="filter-bar-premium">
                <div className="filter-group search">
                    <span className="filter-icon"><Search size={20} /></span>
                    <input
                        type="text"
                        placeholder="Pesquisar por número do armário..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        autoComplete="off"
                        spellCheck="false"
                        autoCorrect="off"
                        autoCapitalize="off"
                    />
                </div>

                <div className="filter-group">
                    <span className="filter-icon"><MapPin size={20} /></span>
                    <select
                        value={filters.floorId}
                        onChange={(e) => setFilters({ ...filters, floorId: e.target.value })}
                    >
                        <option value="All">Todos os Andares</option>
                        {Object.entries(lookups.floors || {}).map(([id, name]) => (
                            <option key={id} value={id}>{name}</option>
                        ))}
                    </select>
                </div>

                <div className="filter-group" style={{ opacity: exchangeSize ? 0.5 : 1, pointerEvents: exchangeSize ? 'none' : 'auto' }}>
                    <span className="filter-icon"><Maximize2 size={20} /></span>
                    <select
                        value={exchangeSize ? 'same' : filters.sizeId}
                        onChange={(e) => setFilters({ ...filters, sizeId: e.target.value })}
                        disabled={!!exchangeSize}
                    >
                        {exchangeSize ? (
                            <option value="same">Apenas {exchangeSize}</option>
                        ) : (
                            <>
                                <option value="All">Todos os Tamanhos</option>
                                {Object.entries(lookups.sizes || {}).map(([id, name]) => (
                                    <option key={id} value={id}>{name}</option>
                                ))}
                            </>
                        )}
                    </select>
                </div>
            </section>

            <div className="matrix-container">
                {isLoading ? (
                    <div className="loading-state-matrix">
                        <Loader2 className="spinner" size={40} />
                        <p>Mapeando estrutura...</p>
                    </div>
                ) : (
                    <div className="locker-wall">
                        {displayLockers.length > 0 ? (
                            displayLockers.map((locker) => (
                                <button
                                    key={locker.dbId}
                                    className={`locker-unit ${getStatusClass(locker.status)} ${selectedLocker?.id === locker.id ? 'active' : ''}`}
                                    onClick={() => openLockerDetails(locker)}
                                >
                                    <span className="unit-number">{locker.id}</span>
                                    {(locker.status === 'ocupado' || locker.status === 'reservado') && <Lock size={12} className="unit-icon" />}
                                    {locker.status === 'vistoria' && <Clock size={12} className="unit-icon" />}
                                    {locker.status === 'manutencao' && <Wrench size={12} className="unit-icon" />}
                                </button>
                            ))
                        ) : (
                            <div className="empty-state-premium">
                                <div className="empty-state-icon">
                                    <Search size={48} />
                                </div>
                                <div className="empty-state-content">
                                    <h3>Nenhum armário encontrado</h3>
                                    <p>Não encontramos unidades com os filtros selecionados. Tente ajustar sua busca ou limpar os filtros.</p>
                                    <button
                                        className="btn-reset-filters"
                                        onClick={() => {
                                            setFilters({ floorId: 'All', sizeId: 'All', contract: 'Semestral' });
                                            setSearchTerm('');
                                        }}
                                    >
                                        Limpar todos os filtros
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Selection Drawer / Side Panel */}
            <div className={`selection-drawer-overlay ${isPanelOpen ? 'open' : ''}`} onClick={() => setIsPanelOpen(false)}>
                <div className="selection-drawer" onClick={e => e.stopPropagation()}>
                    {selectedLocker && (
                        <>
                            <header className="drawer-header">
                                <div className="drawer-header-main">
                                    <div className="drawer-badge">ARMÁRIO #{selectedLocker.id}</div>
                                    <h2>Detalhes da Unidade</h2>
                                </div>
                                <button className="close-drawer-btn" onClick={() => setIsPanelOpen(false)}>
                                    <X size={20} />
                                </button>
                            </header>

                            <div className="drawer-content">
                                {selectedLocker.status === 'reservado' && (
                                    <div className="info-card-premium pink" style={{ marginBottom: '1.5rem' }}>
                                        <Sparkles size={18} />
                                        <div className="info-content">
                                            <h4>Unidade Reservada para Você!</h4>
                                            <p>Este armário foi liberado da fila de espera e está aguardando sua contratação.</p>
                                        </div>
                                    </div>
                                )}

                                <div className="drawer-section">
                                    <h3 className="section-title">Localização e Specs</h3>
                                    <div className="specs-grid">
                                        <div className="spec-item">
                                            <div className="spec-info">
                                                <label>Andar</label>
                                                <span>{selectedLocker.floor}</span>
                                            </div>
                                        </div>
                                        <div className="spec-item">
                                            <Maximize2 size={18} className="spec-icon" />
                                            <div className="spec-info">
                                                <label>Tamanho</label>
                                                <span>{selectedLocker.size}</span>
                                            </div>
                                        </div>
                                        <div className="spec-item">
                                            <Search size={18} className="spec-icon" />
                                            <div className="spec-info">
                                                <label>Posição no Bloco</label>
                                                <span>{selectedLocker.position}</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {!exchangeFor && (
                                    <div className="drawer-section">
                                        <h3 className="section-title">Planos Disponíveis</h3>
                                        <div className="contract-grid">
                                            <div
                                                className={`plan-card ${filters.contract === 'Semestral' ? 'active' : ''}`}
                                                onClick={() => setFilters({ ...filters, contract: 'Semestral' })}
                                            >
                                                <div className="plan-selection-info">
                                                    <span className="plan-name">Semestral</span>
                                                    <div className="plan-price-info">
                                                        <span className="currency">R$</span>
                                                        <span className="amount">{selectedLocker.priceSem}</span>
                                                    </div>
                                                </div>
                                                <div className="plan-radio" />
                                            </div>

                                            <div
                                                className={`plan-card ${filters.contract === 'Anual' ? 'active' : ''}`}
                                                onClick={() => setFilters({ ...filters, contract: 'Anual' })}
                                            >
                                                <div className="plan-selection-info">
                                                    <span className="plan-name">Anual</span>
                                                    <div className="plan-price-info">
                                                        <span className="currency">R$</span>
                                                        <span className="amount">{selectedLocker.priceAnn}</span>
                                                    </div>
                                                </div>
                                                <div className="plan-radio" />
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {exchangeFor && (
                                    <div className="drawer-section info-exchange">
                                        <div className="info-card-premium blue">
                                            <Clock size={18} />
                                            <div className="info-content">
                                                <h4>Taxa de Troca: R$ 20,00</h4>
                                                <p>Ao confirmar, seu armário atual será liberado para vistoria e o novo será ativado instantaneamente.</p>
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>

                            <footer className="drawer-footer">
                                <button
                                    className="confirm-selection-btn"
                                    disabled={selectedLocker.status !== 'disponivel' && selectedLocker.status !== 'reservado'}
                                    onClick={() => {
                                        if (exchangeFor) {
                                            navigate('/dashboard/checkout/payment', {
                                                state: {
                                                    locker: selectedLocker,
                                                    type: 'exchange',
                                                    exchangeInfo: {
                                                        rentalId: exchangeFor,
                                                        oldLockerId: oldLockerId
                                                    }
                                                }
                                            });
                                        } else {
                                            navigate('/dashboard/checkout/contract', {
                                                state: {
                                                    locker: {
                                                        ...selectedLocker,
                                                        plan: filters.contract
                                                    }
                                                }
                                            });
                                        }
                                    }}
                                >
                                    {(selectedLocker.status === 'disponivel' || selectedLocker.status === 'reservado') 
                                        ? (exchangeFor ? 'Confirmar Troca (R$ 20,00)' : 'Prosseguir para o Contrato') 
                                        : 'Unidade Indisponível'}
                                    <ChevronRight size={20} />
                                </button>
                            </footer>
                        </>
                    )}
                </div>
            </div>
            {/* Status Modal for non-available lockers */}
            {
                statusModal && (
                    <div className="status-modal-overlay" onClick={() => setStatusModal(null)}>
                        <div className="status-modal" onClick={e => e.stopPropagation()}>
                            <div className={`status-modal-icon ${getStatusClass(statusModal.status)}`}>
                                {(statusModal.status === 'ocupado' || statusModal.status === 'reservado') && <Lock size={40} />}
                                {statusModal.status === 'vistoria' && <Clock size={40} />}
                                {statusModal.status === 'manutencao' && <Wrench size={40} />}
                            </div>
                            <h2>Armário {statusModal.id}</h2>
                            <p className="status-modal-message">
                                {statusModal.status === 'ocupado' && 'Esta unidade já está ocupada por outro aluno para o período selecionado.'}
                                {statusModal.status === 'reservado' && 'Esta unidade está reservada para uma pessoa na fila de espera.'}
                                {statusModal.status === 'vistoria' && 'Unidade em processo de vistoria. Estará disponível em breve.'}
                                {statusModal.status === 'manutencao' && 'Unidade em manutenção técnica no momento.'}
                            </p>

                            {(statusModal.status === 'ocupado' || statusModal.status === 'reservado') && (
                                <div className="waiting-list-container">
                                    {waitingListStatus ? (
                                        <div className="waiting-list-status">
                                            <CheckCircle2 size={18} />
                                            {waitingListStatus.id_status === 1 ? 'Você está na fila de espera!' : 'Reserva ativa para você!'}
                                        </div>
                                    ) : (
                                        <button 
                                            className="btn-waiting-list" 
                                            onClick={handleJoinWaitingList}
                                            disabled={isProcessingWaitingList}
                                        >
                                            {isProcessingWaitingList ? <Loader2 size={18} className="spinner" /> : <Clock size={16} />}
                                            Entrar na Fila de Espera
                                        </button>
                                    )}
                                </div>
                            )}

                            <button className="status-modal-close" onClick={() => setStatusModal(null)} style={{ marginTop: '1rem' }}>
                                Entendido
                            </button>
                        </div>
                    </div>
                )
            }
        </div >
    );
};

export default UserLockerSelection;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Eye, EyeOff, Clock, RefreshCcw, MapPin, Loader2, Sparkles, ChevronRight, AlertCircle, Info, Maximize2, Lock, ArrowLeftRight, Save, Edit3 } from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import './UserMyLockers.css';

const UserMyLockers = ({ user }) => {
    const navigate = useNavigate();
    const [myLockers, setMyLockers] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [viewPassword, setViewPassword] = useState(null);
    const [isEditingPassword, setIsEditingPassword] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [newPassValue, setNewPassValue] = useState('');
    const [isSavingPass, setIsSavingPass] = useState(false);

    const fetchData = async () => {
        if (!user?.id_usuario) return;
        setIsLoading(true);
        try {
            const { data, error } = await dbService.rentals.getByUser(user.id_usuario);
            if (!error && data) {
                const formatted = data.map(r => {
                    const [sY, sM, sD] = r.dt_inicio.split('-').map(Number);
                    const start = new Date(sY, sM - 1, sD);
                    
                    const [eY, eM, eD] = r.dt_termino.split('-').map(Number);
                    const expiry = new Date(eY, eM - 1, eD);

                    const today = new Date();
                    const diffTime = expiry - today;
                    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

                    const totalTime = expiry - start;
                    const elapsedTime = today - start;
                    const progress = totalTime > 0 ? Math.max(0, Math.min(100, (elapsedTime / totalTime) * 100)) : 0;

                    const isActive = r.id_status_locacao === 1;
                    const isExpired = !isActive || diffDays <= 0;

                    return {
                        id: r.id_locacao,
                        id_armario: r.id_armario,
                        lockerNumber: (r.nr_armario || '---').toString().padStart(3, '0'),
                        floor: r.dc_andar || 'N/A',
                        position: r.nm_posicao || 'MÉDIO',
                        size: r.dc_tamanho || 'Pequeno',
                        password: r.cd_senha || '1234',
                        status: isActive ? 'ATIVA' : 'ENCERRADA',
                        validUntil: expiry.toLocaleDateString(),
                        daysLeft: diffDays > 0 ? diffDays : 0,
                        isExpired: isExpired,
                        rawExpiry: expiry,
                        progress: progress
                    };
                });
                setMyLockers(formatted);
            }
        } catch (err) {
            console.error('[FETCH MY LOCKERS ERROR]', err);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [user]);

    const handleOpenPass = (locker) => {
        setViewPassword(locker);
        setNewPassValue(locker.password);
        setIsEditingPassword(false);
    };

    const handleSavePassword = async () => {
        if (!viewPassword) return;
        setIsSavingPass(true);
        try {
            const { error } = await dbService.rentals.updatePassword(viewPassword.id, newPassValue);
            if (!error) {
                setMyLockers(myLockers.map(l => l.id === viewPassword.id ? { ...l, password: newPassValue } : l));
                setIsEditingPassword(false);
                setTimeout(() => setViewPassword(null), 800);
            }
        } catch (err) {
            console.error('[UPDATE PASS ERROR]', err);
        } finally {
            setIsSavingPass(false);
        }
    };

    const handleExchange = (locker) => {
        // Redireciona para seleção com o parâmetro de troca
        navigate(`/dashboard/lockers?exchange_for=${locker.id}&size=${locker.size}&old_id=${locker.id_armario}`);
    };

    if (isLoading) {
        return (
            <div className="my-lockers-premium">
                <div className="loading-state">
                    <Loader2 className="spinner-medical" size={48} />
                    <p>Sincronizando suas locações...</p>
                </div>
            </div>
        );
    }

    const activeCount = myLockers.filter(l => !l.isExpired).length;

    return (
        <div className="my-lockers-container premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>Meus Armários</h1>
                    <p>Olá, <strong>{user?.name?.split(' ')[0] || 'Aluno'}</strong>! Você possui {activeCount} {activeCount === 1 ? 'armário ativo' : 'armários ativos'}.</p>
                </div>
                <div className="header-actions-pill">
                    <div className="stat-badge">
                        <div className="locker-icon-standard" style={{ width: '14px', height: '14px' }} />
                        <span>{myLockers.length} {myLockers.length === 1 ? 'Locação' : 'Locações'}</span>
                    </div>
                </div>
            </header>

            <div className="lockers-section">
                    {myLockers.length > 0 ? (
                        <div className="lockers-matrix">
                            {myLockers.map((locker, index) => (
                                <div
                                    key={locker.id}
                                    className={`locker-card-premium ${locker.isExpired ? 'expired' : ''}`}
                                >
                                    <div className="card-glass-effect" />

                                    <div className="locker-header">
                                        <div className="locker-main-info">
                                            <div className="locker-avatar">
                                                <div className="locker-icon-standard white" style={{ width: '24px', height: '24px' }} />
                                            </div>
                                            <div className="locker-titles">
                                                <span className="locker-id">Armário #{locker.lockerNumber}</span>
                                                <span className={`status-tag ${locker.status.toLowerCase()}`}>
                                                    {locker.status}
                                                </span>
                                            </div>
                                        </div>
                                        <div className="locker-specs">
                                            <div className="spec-item" title="Localização">
                                                <span>{locker.floor}</span>
                                            </div>
                                            <div className="spec-item" title="Tamanho">
                                                <Maximize2 size={14} />
                                                <span>{locker.size}</span>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="locker-timeline">
                                        <div className="timeline-info">
                                            <div className="expiry-date">
                                                <Clock size={16} />
                                                <span>{locker.isExpired ? 'Venceu em' : 'Vence em'} <strong>{locker.validUntil}</strong></span>
                                            </div>
                                            {!locker.isExpired && (
                                                <span className="days-counter">
                                                    {locker.daysLeft} dias
                                                </span>
                                            )}
                                        </div>
                                        {!locker.isExpired && (
                                            <div className="progress-bar-container">
                                                <div
                                                    className="progress-fill"
                                                    style={{ width: `${locker.progress}%` }}
                                                />
                                            </div>
                                        )}
                                    </div>

                                    <div className="locker-actions-grid">
                                        <button
                                            className="btn-action-glass"
                                            onClick={() => handleOpenPass(locker)}
                                        >
                                            <Lock size={16} />
                                            <span>Minha senha</span>
                                        </button>
                                        {!locker.isExpired && (
                                            <button 
                                                className="btn-action-glass"
                                                onClick={() => handleExchange(locker)}
                                            >
                                                <ArrowLeftRight size={16} />
                                                <span>Trocar armário</span>
                                            </button>
                                        )}
                                    </div>

                                </div>
                            ))}

                            <div
                                className="add-locker-card-premium"
                                onClick={() => navigate('/dashboard/lockers')}
                            >
                                <div className="add-content">
                                    <div className="add-icon-sphere">
                                        <img src="/deal.png" alt="Deal" style={{ width: '32px', height: '32px', objectFit: 'contain' }} />
                                    </div>
                                    <h3>Novo Aluguel</h3>
                                    <ChevronRight size={20} className="arrow" />
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="empty-lockers-premium">
                            <div className="empty-illustration">
                                <div className="empty-icon-ring">
                                    <span className="empty-emoji">🔒</span>
                                </div>
                            </div>
                            <h2>Nenhum armário ainda</h2>
                            <p>Você ainda não possui nenhuma locação ativa.<br />Escolha seu armário agora e garanta seu espaço!</p>
                            <button className="btn-cta-premium" onClick={() => navigate('/dashboard/lockers')}>
                                Ver Armários Disponíveis
                                <ChevronRight size={18} />
                            </button>
                        </div>
                    )}
            </div>

            {/* Password Modal */}
            {/* Password Modal */}
                {viewPassword && (
                    <div className="modal-overlay" onClick={() => setViewPassword(null)}>
                        <div
                            className="password-modal"
                            onClick={(e) => e.stopPropagation()}
                        >
                            <div className="modal-header">
                                <Lock size={24} className="lock-icon-medical" />
                                <h2>{isEditingPassword ? 'Editar Senha' : 'Senha do Armário'}</h2>
                                <p>Armário #{viewPassword.lockerNumber}</p>
                            </div>
                            
                            <div className="password-display" onClick={() => !isEditingPassword && setIsEditingPassword(true)}>
                                {isEditingPassword ? (
                                    <div className="password-edit-container">
                                        <input 
                                            type="text" 
                                            className="p-input"
                                            value={newPassValue}
                                            onChange={(e) => setNewPassValue(e.target.value)}
                                            autoFocus
                                            maxLength={8}
                                        />
                                        <p className="edit-hint">Anote sua nova combinação acima.</p>
                                    </div>
                                ) : (
                                    <div className="password-view-wrapper">
                                        <span className="p-code">
                                            {showPassword ? viewPassword.password : '••••'}
                                        </span>
                                        <p className="edit-hint-click">Clique para editar</p>
                                    </div>
                                )}
                            </div>

                            <div className="modal-footer">
                                {isEditingPassword ? (
                                    <div className="footer-actions">
                                        <button className="btn-cancel" onClick={() => setIsEditingPassword(false)} disabled={isSavingPass}>
                                            Cancelar
                                        </button>
                                        <button className="btn-save" onClick={handleSavePassword} disabled={isSavingPass}>
                                            {isSavingPass ? <Loader2 className="spinner" size={18} /> : <Save size={18} />}
                                            Salvar Senha
                                        </button>
                                    </div>
                                ) : (
                                    <div className="footer-actions">
                                        <button className="btn-toggle-eye" onClick={() => setShowPassword(!showPassword)}>
                                            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                            {showPassword ? 'Ocultar' : 'Visualizar'}
                                        </button>
                                        <button className="btn-close-modal" onClick={() => setViewPassword(null)}>
                                            Fechar
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                )}
        </div>
    );
};

